import{c as a,Q as t,j as i,m as s}from"./chunks/framework.BPKcPtvA.js";const c=JSON.parse('{"title":"OpenClaw — troubleshooting","description":"Symptom → fix for skill install and Telegram bot issues.","frontmatter":{"title":"OpenClaw — troubleshooting","description":"Symptom → fix for skill install and Telegram bot issues."},"headers":[],"relativePath":"openclaw/troubleshooting.md","filePath":"openclaw/troubleshooting.md","lastUpdated":1780192711000}'),o={name:"openclaw/troubleshooting.md"};function n(l,e,r,h,d,p){return t(),i("div",null,[...e[0]||(e[0]=[s('<div class="warning custom-block"><p class="custom-block-title">🚧 In development — not in the Testing Guide</p><p>This surface is still being hardened and isn&#39;t part of the <a href="/guide/">Testing Guide</a>. The page below describes the intended design. To evaluate MuHaven today, use <a href="/havenbot/overview">HavenBot</a> or the <a href="/mcp/overview">MCP server</a>.</p></div><h1 id="openclaw-telegram-troubleshooting" tabindex="-1">OpenClaw + Telegram troubleshooting <a class="header-anchor" href="#openclaw-telegram-troubleshooting" aria-label="Permalink to &quot;OpenClaw + Telegram troubleshooting&quot;">​</a></h1><h2 id="skill-install" tabindex="-1">Skill install <a class="header-anchor" href="#skill-install" aria-label="Permalink to &quot;Skill install&quot;">​</a></h2><h3 id="clawhub-install-succeeded-but-the-skill-won-t-start" tabindex="-1">&quot;ClawHub install succeeded but the skill won&#39;t start&quot; <a class="header-anchor" href="#clawhub-install-succeeded-but-the-skill-won-t-start" aria-label="Permalink to &quot;&quot;ClawHub install succeeded but the skill won&#39;t start&quot;&quot;">​</a></h3><p>Since skill <code>0.1.1</code> the tarball inline-bundles <code>@muhaven/mcp</code> + its transitive deps (tsup <code>noExternal</code>), so the legacy &quot;run <code>npm install --omit=dev</code> in the skill dir&quot; workaround is no longer needed. If the skill won&#39;t start, check the <code>muhaven-broker</code> daemon (next item) — that&#39;s now the most common cause.</p><h3 id="muhaven-broker-not-found" tabindex="-1">&quot;muhaven-broker not found&quot; <a class="header-anchor" href="#muhaven-broker-not-found" aria-label="Permalink to &quot;&quot;muhaven-broker not found&quot;&quot;">​</a></h3><p>The skill&#39;s bundled <code>@muhaven/mcp</code> only exposes the MCP server — the <strong>broker daemon bin</strong> has to be installed separately so it lands on <code>$PATH</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @muhaven/mcp@0.1.4</span></span></code></pre></div><p>Then run <code>muhaven-broker setup</code> to start + authorize the daemon. This is also documented in the skill&#39;s <code>config.json#post_install_review.items</code> (<code>broker-bin-on-path</code>).</p><h3 id="sigstore-signature-verification-failed" tabindex="-1">&quot;Sigstore signature verification failed&quot; <a class="header-anchor" href="#sigstore-signature-verification-failed" aria-label="Permalink to &quot;&quot;Sigstore signature verification failed&quot;&quot;">​</a></h3><p>The ClawHub install verifies the skill against the GitHub OIDC issuer <code>hasToDev/muhaven</code>. If verification fails:</p><ol><li>Confirm you&#39;re installing from ClawHub (not a tarball from a random source).</li><li>Run <code>clawhub --version</code> — older clawhub versions had buggy Sigstore verification; update to <code>clawhub@0.12.3</code> or later.</li><li>If you&#39;re on a fork of the repo, the OIDC issuer won&#39;t match — use the upstream skill, not the fork.</li></ol><h3 id="subset-filter-says-empty-registry" tabindex="-1">&quot;Subset filter says &#39;empty registry&#39;&quot; <a class="header-anchor" href="#subset-filter-says-empty-registry" aria-label="Permalink to &quot;&quot;Subset filter says &#39;empty registry&#39;&quot;&quot;">​</a></h3><p>The <code>@muhaven/mcp</code> version bundled with the skill doesn&#39;t match the version the subset filter expects. The skill enforces a triple-match (<code>SKILL.md</code> frontmatter ↔ <code>manifest.json#mcp.bundled_version</code> ↔ <code>package.json#version</code> of the installed bundled package).</p><p>Fix: install the exact bundled version:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @muhaven/mcp@</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bundled_version</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.openclaw/skills/muhaven-rwa-skill/manifest.json</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> head</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> awk</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -F</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;&quot;&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{print $4}&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>Or update the skill: <code>clawhub install muhaven-rwa-skill@latest</code>.</p><h2 id="telegram-bot" tabindex="-1">Telegram bot <a class="header-anchor" href="#telegram-bot" aria-label="Permalink to &quot;Telegram bot&quot;">​</a></h2><h3 id="link-reports-expired-code" tabindex="-1">&quot;/link reports <code>expired code</code>&quot; <a class="header-anchor" href="#link-reports-expired-code" aria-label="Permalink to &quot;&quot;/link reports `expired code`&quot;&quot;">​</a></h3><p>Link codes are TTL 5 minutes. If you took longer than that to paste it into the dashboard, request a new one:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/link</span></span></code></pre></div><h3 id="buy-says-not-linked" tabindex="-1">&quot;/buy says <code>not linked</code>&quot; <a class="header-anchor" href="#buy-says-not-linked" aria-label="Permalink to &quot;&quot;/buy says `not linked`&quot;&quot;">​</a></h3><p>You haven&#39;t completed the <code>/link</code> ceremony, or you unlinked. Re-run <code>/link</code> and paste the code into the dashboard.</p><h3 id="inline-button-does-nothing-when-tapped" tabindex="-1">&quot;Inline button does nothing when tapped&quot; <a class="header-anchor" href="#inline-button-does-nothing-when-tapped" aria-label="Permalink to &quot;&quot;Inline button does nothing when tapped&quot;&quot;">​</a></h3><p>Three likely causes:</p><ol><li><strong>Tap is from a different Telegram user.</strong> The bot enforces <code>from.id === chat.id &amp;&amp; chat.type === &#39;private&#39;</code>. Group-chat taps are refused.</li><li><strong>Intent expired.</strong> The 5-min TTL ran out between <code>/buy</code> and your tap.</li><li><strong>Bot service-secret is misconfigured.</strong> This is an operator issue; report it.</li></ol><h3 id="mini-app-opens-but-says-intent-not-found" tabindex="-1">&quot;Mini App opens but says <code>intent not found</code>&quot; <a class="header-anchor" href="#mini-app-opens-but-says-intent-not-found" aria-label="Permalink to &quot;&quot;Mini App opens but says `intent not found`&quot;&quot;">​</a></h3><p>The intent expired (5-min TTL) or the URL fragment is malformed. Re-issue the buy:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/buy 1000 RWA1</span></span></code></pre></div><h3 id="mini-app-otp-says-invalid" tabindex="-1">&quot;Mini App OTP says <code>invalid</code>&quot; <a class="header-anchor" href="#mini-app-otp-says-invalid" aria-label="Permalink to &quot;&quot;Mini App OTP says `invalid`&quot;&quot;">​</a></h3><p>OTPs are single-use, 6 digits, expire in 5 minutes:</p><ul><li>Wrong code → re-check the OTP in your password manager (or wherever it was delivered).</li><li>Expired → re-issue the buy.</li><li>Already used → the intent already settled; check <code>/audit</code> for confirmation.</li></ul><h3 id="passkey-deeplink-opens-but-the-page-is-blank" tabindex="-1">&quot;Passkey deeplink opens but the page is blank&quot; <a class="header-anchor" href="#passkey-deeplink-opens-but-the-page-is-blank" aria-label="Permalink to &quot;&quot;Passkey deeplink opens but the page is blank&quot;&quot;">​</a></h3><p>Two possibilities:</p><ol><li><strong>The dashboard is unreachable.</strong> Check <code>https://api.muhaven.app/health</code>.</li><li><strong>The intent doesn&#39;t belong to your MuHaven wallet.</strong> The dashboard validates that the intent&#39;s <code>userId</code> matches the JWT&#39;s <code>userId</code>; mismatch returns 404.</li></ol><h3 id="bot-replies-423-paused-on-every-command" tabindex="-1">&quot;Bot replies <code>423 PAUSED</code> on every command&quot; <a class="header-anchor" href="#bot-replies-423-paused-on-every-command" aria-label="Permalink to &quot;&quot;Bot replies `423 PAUSED` on every command&quot;&quot;">​</a></h3><p>Your agent is paused. Either:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/pause           # idempotent — no-op if already paused</span></span></code></pre></div><p>doesn&#39;t unpause. To resume, sign in to the dashboard at <code>muhaven.app/agent</code> and complete the resume ceremony (passkey signature).</p><p>The bot can pause but cannot resume — resume requires a WebAuthn ceremony that needs a browser.</p><h2 id="three-tier-classifier" tabindex="-1">Three-tier classifier <a class="header-anchor" href="#three-tier-classifier" aria-label="Permalink to &quot;Three-tier classifier&quot;">​</a></h2><h3 id="buy-with-amount-200-01-went-to-mini-app-otp-not-inline" tabindex="-1">&quot;Buy with amount $200.01 went to Mini-App OTP, not Inline&quot; <a class="header-anchor" href="#buy-with-amount-200-01-went-to-mini-app-otp-not-inline" aria-label="Permalink to &quot;&quot;Buy with amount $200.01 went to Mini-App OTP, not Inline&quot;&quot;">​</a></h3><p>That&#39;s expected — the inline ceiling is <strong>≤ $200 inclusive</strong>, and $200.01 &gt; $200. The boundaries are hard-coded; investors cannot raise them.</p><h3 id="i-want-all-my-buys-to-go-through-the-dashboard-passkey" tabindex="-1">&quot;I want all my buys to go through the dashboard passkey&quot; <a class="header-anchor" href="#i-want-all-my-buys-to-go-through-the-dashboard-passkey" aria-label="Permalink to &quot;&quot;I want all my buys to go through the dashboard passkey&quot;&quot;">​</a></h3><p>There&#39;s no per-user override for the classifier today. The closest equivalent: set your tier to <code>Advisory</code> on the dashboard, which makes every <code>position.*</code> proposal prompt your passkey regardless of source surface. Telegram inline taps will still be rejected at the policy gate.</p><h3 id="i-want-sub-200-buys-to-require-mini-app-otp-for-extra-friction" tabindex="-1">&quot;I want sub-$200 buys to require Mini-App OTP for extra friction&quot; <a class="header-anchor" href="#i-want-sub-200-buys-to-require-mini-app-otp-for-extra-friction" aria-label="Permalink to &quot;&quot;I want sub-$200 buys to require Mini-App OTP for extra friction&quot;&quot;">​</a></h3><p>Not supported today. The classifier is one-way — raising friction within a tier isn&#39;t a per-user knob.</p><h2 id="subset-manifest" tabindex="-1">Subset &amp; manifest <a class="header-anchor" href="#subset-manifest" aria-label="Permalink to &quot;Subset &amp; manifest&quot;">​</a></h2><h3 id="skill-bundled-wrong-version-of-muhaven-mcp" tabindex="-1">&quot;Skill bundled wrong version of @muhaven/mcp&quot; <a class="header-anchor" href="#skill-bundled-wrong-version-of-muhaven-mcp" aria-label="Permalink to &quot;&quot;Skill bundled wrong version of @muhaven/mcp&quot;&quot;">​</a></h3><p>The verify-subset gate enforces the triple-match at the skill&#39;s build time. If you see a runtime mismatch (e.g., bundled version is <code>0.1.0</code> but <code>@muhaven/mcp</code> globally installed is <code>0.1.2</code>):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Update both to the latest skill release</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawhub</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> muhaven-rwa-skill@latest</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @muhaven/mcp@latest</span></span></code></pre></div><p>If the global <code>@muhaven/mcp</code> is <em>newer</em> than the skill&#39;s bundled version, the broker may still work — but the SHA-256 tool-hash pin will fail. Wait for the next skill release that bundles the new MCP version.</p><h2 id="where-next" tabindex="-1">Where next <a class="header-anchor" href="#where-next" aria-label="Permalink to &quot;Where next&quot;">​</a></h2><ul><li><a href="/openclaw/install-skill">Install the skill</a> — full install walkthrough.</li><li><a href="/openclaw/telegram-bot">Telegram bot</a> — link your Telegram, send commands.</li><li><a href="/openclaw/confirmation-tiers">Three confirmation tiers</a> — the tier classifier in detail.</li></ul>',54)])])}const b=a(o,[["render",n]]);export{c as __pageData,b as default};
